// Check if ∀x P(x) is true
// Domain: array of elements
// P(x): predicate function
FUNCTION CheckUniversalQuantifier(domain, P):
 FOR each x IN domain:
 IF NOT P(x) THEN:
 RETURN false // Counterexample found
 END IF
 END FOR
 RETURN true // All elements satisfy P(x)

// Check if ∃x P(x) is true
// Domain: array of elements
// P(x): predicate function
FUNCTION CheckExistentialQuantifier(domain, P):
 FOR each x IN domain:
 IF P(x) THEN:
 RETURN true // Found an element satisfying P(x)
 END IF
 END FOR
 RETURN false // No element satisfies P(x)

// Negation rules for quantifiers:
// ¬∀x P(x) ≡ ∃x ¬P(x)
// ¬∃x P(x) ≡ ∀x ¬P(x)

FUNCTION NegateUniversal(domain, P):
 // Returns true if ¬∀x P(x) is true
 // Which is equivalent to ∃x ¬P(x)
 FOR each x IN domain:
 IF NOT P(x) THEN:
 RETURN true
 END IF
 END FOR
 RETURN false

FUNCTION NegateExistential(domain, P):
 // Returns true if ¬∃x P(x) is true
 // Which is equivalent to ∀x ¬P(x)
 FOR each x IN domain:
 IF P(x) THEN:
 RETURN false
 END IF
 END FOR
 RETURN true
